  # Remove the pending user
  def test_remove_verification
    # Parameters for the API call
    user_id = nil

    # Perform the API call through the SDK function
    result = @controller.remove_verification(user_id)

    # Test response code
    assert_equal(204, @response_catcher.response.status_code)
    # Test headers
    expected_headers = {}
    expected_headers['content-type'] = 'application/json; charset=utf-8'

    assert(ComparisonHelper.match_headers(expected_headers, @response_catcher.response.headers))

    # Test whether the captured response is as we expected
    refute_nil(result)
    expected_body = JSON.parse(
      '{"type":"RemoveVerification","data":{"id":"11e95f8ec39de8fbdb0a4f1a","u'\
      'ser_id":"11e95f8ec39de8fbdb0a4f1a","hash":"123456781234567812345678","c'\
      'reated_ts":1422040992}}'
    )
    received_body = JSON.parse(@response_catcher.response.raw_body)
    assert(ComparisonHelper.match_body(expected_body, received_body))
  end

  # Send an verification email to the pending user
  def test_send_verification
    # Parameters for the API call
    user_id = nil

    # Perform the API call through the SDK function
    result = @controller.send_verification(user_id)

    # Test response code
    assert_equal(201, @response_catcher.response.status_code)
    # Test headers
    expected_headers = {}
    expected_headers['content-type'] = 'application/json; charset=utf-8'

    assert(ComparisonHelper.match_headers(expected_headers, @response_catcher.response.headers))

    # Test whether the captured response is as we expected
    refute_nil(result)
    expected_body = JSON.parse(
      '{"type":"SendVerification","data":{"id":"11e95f8ec39de8fbdb0a4f1a","use'\
      'r_id":"11e95f8ec39de8fbdb0a4f1a","hash":"123456781234567812345678","cre'\
